// holo-std/math — integer math primitives (Holo-C). A content-addressed library: its κ is the
// hash of these exact bytes; anything that links it pins it by content (Law L1), re-derives it
// (Law L5), and shares it once across the whole dependency graph (Law L3).
int abs(int x) { if (x < 0) return -x; return x; }
int min(int a, int b) { if (a < b) return a; return b; }
int max(int a, int b) { if (a > b) return a; return b; }
int gcd(int a, int b) { while (b != 0) { int t = a % b; a = b; b = t; } return a; }
int isqrt(int n) { int r = 0; while ((r + 1) * (r + 1) <= n) { r = r + 1; } return r; }
int ipow(int base, int exp) { int r = 1; while (exp > 0) { r = r * base; exp = exp - 1; } return r; }

// holo-std/prime — primality + prime enumeration (Holo-C). Depends on holo-std/math (uses isqrt).
// The dependency is resolved by content address and the shared math library is linked exactly once.
int isPrime(int n) {
  if (n < 2) return 0;
  int i = 2;
  int r = isqrt(n);                 // from holo-std/math
  while (i <= r) { if (n % i == 0) return 0; i = i + 1; }
  return 1;
}
int nthPrime(int k) {               // 1-indexed: nthPrime(1) = 2, nthPrime(10) = 29
  int count = 0; int n = 1;
  while (count < k) { n = n + 1; if (isPrime(n)) count = count + 1; }
  return n;
}

// holo-std/combo — combinatorics (Holo-C). Depends on holo-std/math (uses min). Linking combo and
// prime together pulls holo-std/math once (Law L3 dedup) — a real transitive dependency graph.
int factorial(int n) { int r = 1; while (n > 1) { r = r * n; n = n - 1; } return r; }
int choose(int n, int k) {          // n-choose-k, computed without overflow-prone full factorials
  k = min(k, n - k);                // from holo-std/math
  int num = 1; int den = 1; int i = 0;
  while (i < k) { num = num * (n - i); den = den * (i + 1); i = i + 1; }
  return num / den;
}
